/* =============================== SECTION 2 widget =============================== */
(function(){
  const svg = $('#met-svg'), sel = $('#met-sel'), out = $('#met-out');
  const W = 620, H = 360;
  const N = 16;
  // render a grid of ellipses; each ellipse indicates the unit ball of g at that grid point
  // The grid is placed in SVG pixel coordinates; each manifold has its natural parameter domain mapped to the drawing box.
  function metricAt(kind, u, v){
    // returns {a,b,c} for the 2x2 symmetric matrix [[a,b],[b,c]]
    if(kind==='euclid'){
      return {a:1, b:0, c:1};
    } else if(kind==='sphere'){
      // (theta, phi) in (0,pi) x (0, 2pi); domain u in (0.05, pi-.05), v free
      const theta = u;
      return {a:1, b:0, c: Math.sin(theta)*Math.sin(theta)};
    } else if(kind==='hyp'){
      // half-plane; v > 0; ds^2 = (du^2 + dv^2)/v^2
      const y = v;
      const s = 1/(y*y);
      return {a:s, b:0, c:s};
    }
  }
  // domain for each kind
  function domainOf(kind){
    if(kind==='euclid') return {u0:-1, u1:1, v0:-1, v1:1, label:'(x, y) in [-1,1]^2'};
    if(kind==='sphere') return {u0:0.12, u1:Math.PI-0.12, v0:0, v1:2*Math.PI, label:'(θ, φ) ∈ (0,π) × (0,2π)'};
    if(kind==='hyp')    return {u0:-1.5, u1:1.5, v0:0.15, v1:2.5, label:'(x, y), y > 0'};
  }
  function render(){
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    const kind = sel.value;
    const dom = domainOf(kind);
    // background
    const bg = SVG('rect',{x:0,y:0,width:W,height:H,fill:'#0b0f16'});
    svg.appendChild(bg);
    // draw grid points as small ellipses representing the unit ball of g
    // base step in each coordinate
    const du = (dom.u1-dom.u0)/(N-1);
    const dv = (dom.v1-dom.v0)/(N-1);
    // scale: want ellipses about "step" size in pixels for the Euclidean case, then scale by 1/sqrt(eigvals) for others
    const pxU = (W-60)/(N-1);
    const pxV = (H-40)/(N-1);
    // pick a base radius so the Euclidean case is a round circle of fixed size
    const base = 0.42 * Math.min(pxU, pxV);

    // compute a global normalization so the biggest ellipse fits
    // We'll scale each ellipse's axes by (base / sqrt(eigval)) but clamp to [0.12*base, 2.2*base].
    for(let j=0;j<N;j++){
      for(let i=0;i<N;i++){
        const u = dom.u0 + i*du;
        const v = dom.v0 + j*dv;
        const px = 30 + i*pxU;
        const py = H - 20 - j*pxV;
        const m = metricAt(kind, u, v);
        // eigen-decompose [[a,b],[b,c]]
        const tr = m.a + m.c, det = m.a*m.c - m.b*m.b;
        const disc = Math.max(0, tr*tr/4 - det);
        const s = Math.sqrt(disc);
        const l1 = tr/2 + s, l2 = tr/2 - s;
        // unit ball of g: {v: g(v,v) <= 1}.  Principal axes of ellipse have length 1/sqrt(l_i).
        let rx = 1/Math.sqrt(Math.max(1e-4, l1));
        let ry = 1/Math.sqrt(Math.max(1e-4, l2));
        // angle of eigenvector for l1
        let theta = 0;
        if(Math.abs(m.b) > 1e-9){
          theta = Math.atan2(l1 - m.a, m.b);
        } else if(m.a > m.c){
          theta = 0;
        } else {
          theta = Math.PI/2;
        }
        // scale
        let scale = base;
        // for hyperbolic, the raw size gets huge near y=0; clamp.
        rx *= scale; ry *= scale;
        const maxR = 2.6*base;
        rx = Math.min(rx, maxR); ry = Math.min(ry, maxR);
        rx = Math.max(rx, 0.08*base); ry = Math.max(ry, 0.08*base);
        // draw the ellipse, rotated
        // NOTE: we swap rx<->ry if the eigenvector we're rotating to is for rx direction
        // Our convention: principal axis of length 1/sqrt(l1) along eigenvector for l1.
        // rx corresponds to l1, ry to l2; rotate coordinate system by theta so the x-axis aligns with eigenvector of l1.
        const g = SVG('g',{transform:`translate(${px} ${py}) rotate(${(theta*180/Math.PI).toFixed(2)})`});
        const e = SVG('ellipse',{cx:0,cy:0,rx:rx.toFixed(2),ry:ry.toFixed(2),
          fill:'rgba(88,196,221,0.10)',stroke:'var(--blue)','stroke-width':1});
        g.appendChild(e);
        svg.appendChild(g);
      }
    }
    // annotate
    out.textContent = `domain ${dom.label} — ellipses are the unit balls {v : g_p(v,v) ≤ 1} (rescaled for display)`;
  }
  sel.addEventListener('change', render);
  render();
})();

