  if(rr>1) return null;
  const zView = Math.sqrt(1-rr);
  // undo the rotation (we rotated by A about y; here invert)
  const A = -0.35;
  const sA = Math.sin(A), cA = Math.cos(A);
  const xv =  cA*x + sA*zView;
  const yv =  y;
  const zv = -sA*x + cA*zView;
  return [xv,yv,zv];
}

// normalize a 3-vector
function nrm(v){ const L = Math.hypot(v[0],v[1],v[2])||1; return [v[0]/L, v[1]/L, v[2]/L]; }
function dot(a,b){ return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]; }
function cross(a,b){ return [a[1]*b[2]-a[2]*b[1], a[2]*b[0]-a[0]*b[2], a[0]*b[1]-a[1]*b[0]]; }
function scale(a,s){ return [a[0]*s, a[1]*s, a[2]*s]; }
function add(a,b){ return [a[0]+b[0],a[1]+b[1],a[2]+b[2]]; }
function sub(a,b){ return [a[0]-b[0],a[1]-b[1],a[2]-b[2]]; }

// great-circle arc between two unit vectors a,b, parameter t∈[0,1]
function slerp(a,b,t){
  const c = Math.max(-1, Math.min(1, dot(a,b)));
  const omg = Math.acos(c);
  if(omg < 1e-6) return a.slice();
  const s = Math.sin(omg);
  return add(scale(a, Math.sin((1-t)*omg)/s), scale(b, Math.sin(t*omg)/s));
}

// Tangent vector transported along a great-circle arc from a to b, starting with tangent v at a (with v⊥a).
// Parallel transport on the sphere along a great circle simply rotates the tangent plane; components along the arc direction are preserved.
// Equivalently, at point p(t)=slerp(a,b,t), the tangent direction "along the arc" is dp/dt normalized; the "orthogonal" component (p × dp/dt) direction is also preserved.
// So if at a we decompose v = alpha * e_along + beta * e_perp, then at p(t) the transported v is alpha * e_along(t) + beta * e_perp(t).
function transportArc(a,b, v0){
  // basis at a
  const tAng = nrm(sub(b, scale(a, dot(a,b))));
  const nAng = cross(a, tAng);
  const alpha = dot(v0, tAng), beta = dot(v0, nAng);
  return {alpha, beta, arcStart:a, arcEnd:b,
    sample: function(t){
      const p = nrm(slerp(a,b,t));
      const tdir = nrm(sub(b, scale(p, dot(p,b))));
      const ndir = cross(p, tdir);
      return { p, v: add(scale(tdir, alpha), scale(ndir, beta)) };
    },
    final: function(){
      const p = b;
      const tdir = nrm(sub(a, scale(p, dot(p,a))));
      // tangent "coming in" at b: direction from predecessor; but consistent with dp/dt at t=1 means point in the same sense as d/dt slerp
      const tInc = nrm(sub(b, scale(a, dot(a,b))));
      // easier: take limit by finite difference
      const pp = nrm(slerp(a,b,0.999));
      const tEnd = nrm(sub(p, pp));
      const nEnd = cross(p, tEnd);
      return add(scale(tEnd, alpha), scale(nEnd, beta));
    }
  };
}

// spherical area of a triangle with vertices A,B,C (unit vectors); by L'Huilier / excess formula.
function sphArea(A,B,C){
  // sum of interior angles - pi
  function ang(P, Q, R){
    // angle at P between arcs PQ and PR
    const u = nrm(sub(Q, scale(P, dot(P,Q))));
    const w = nrm(sub(R, scale(P, dot(P,R))));
    const c = Math.max(-1, Math.min(1, dot(u,w)));
    return Math.acos(c);
  }
  return ang(A,B,C) + ang(B,A,C) + ang(C,A,B) - Math.PI;
}

// total holonomy: transport a tangent vector around the 3-arc triangle A->B->C->A.
// Returns the final vector at A and the rotation angle vs the initial.
function holonomy(v0){
  const A=verts[0], B=verts[1], C=verts[2];
  // pick initial v0 in T_A S^2
  let v = v0.slice();
  let ab = transportArc(A,B,v); v = ab.final();
  let bc = transportArc(B,C,v); v = bc.final();
  let ca = transportArc(C,A,v); v = ca.final();
  // angle between v and v0 in tangent plane at A
  // project v into T_A
  const vT = sub(v, scale(A, dot(A,v)));
  const v0T = sub(v0, scale(A, dot(A,v0)));
  const n = A;
  const ux = nrm(v0T), uy = nrm(cross(n, ux));
  const x = dot(vT, ux), y = dot(vT, uy);
  const angle = Math.atan2(y, x);
  return {final:v, angle};
}

// tangent reference at each vertex for visualization: e.g., (d phi) direction.
function refTangent(A){
  // perpendicular to A, in the horizontal (x,z) plane if possible
  let cand = [A[2], 0, -A[0]];
  const L = Math.hypot(cand[0], cand[2]);
  if(L < 1e-3) cand = [0,0,1];
  return nrm(cand);
}

let animT = 0, animRAF=0;

function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // sphere disk
  svg.appendChild(SVG('rect',{x:0,y:0,width:W,height:H,fill:'#0b0f16'}));
  svg.appendChild(SVG('circle',{cx:CX,cy:CY,r:R,fill:'rgba(88,196,221,0.06)',stroke:'var(--line)','stroke-width':1}));
  // latitude lines for decoration
  for(let k=1;k<6;k++){
    const lat = -1 + k*2/6;
    const rr = Math.sqrt(1-lat*lat);
    svg.appendChild(SVG('ellipse',{cx:CX,cy:CY - lat*R, rx:rr*R*0.96, ry:rr*R*0.18,
      fill:'none', stroke:'var(--line)', 'stroke-width':0.7}));
  }
  // triangle arcs
  const A=verts[0], B=verts[1], C=verts[2];
  const colors = ['var(--blue)','var(--blue)','var(--blue)'];
  const arcs = [[A,B],[B,C],[C,A]];
  for(let k=0;k<3;k++){
    const pathD = [];
    const [p,q] = arcs[k];
    const STEPS = 48;
    for(let i=0;i<=STEPS;i++){
      const t = i/STEPS;
      const s = nrm(slerp(p,q,t));
      const pr = proj(s);
      pathD.push((i===0?'M':'L')+pr[0].toFixed(1)+' '+pr[1].toFixed(1));
    }
    svg.appendChild(SVG('path',{d:pathD.join(' '),fill:'none',stroke:colors[k],'stroke-width':2}));
  }
  // vertices
  const names = ['A','B','C'];
  for(let k=0;k<3;k++){
    const pr = proj(verts[k]);
    svg.appendChild(SVG('circle',{cx:pr[0], cy:pr[1], r:7, fill:'var(--yellow)', stroke:'#111', 'stroke-width':1.5,
      style:'cursor:grab'}));
    const t = SVG('text',{x:pr[0]+12, y:pr[1]-8, 'font-size':12, fill:'var(--yellow)'});
    t.textContent = names[k];
    svg.appendChild(t);
  }
  // reference tangent at A (starting vector)
  const v0 = refTangent(A);
  // compute the traveling vector across the three arcs at animT
  const segs = [[A,B],[B,C],[C,A]];
  let vCur = v0.slice();
  let arcIdx = 0;
  let tInArc = 0;
  if(animT > 0){
    const totalT = animT;
    const sPerArc = 1/3;
    arcIdx = Math.min(2, Math.floor(totalT / sPerArc));
    tInArc = (totalT - arcIdx*sPerArc)/sPerArc;
    for(let k=0;k<arcIdx;k++){
      vCur = transportArc(segs[k][0], segs[k][1], vCur).final();
    }
  }
  // draw the vector at current position
  const segNow = segs[arcIdx];
  const tAt = transportArc(segNow[0], segNow[1], vCur);
  const smp = tAt.sample(tInArc);
  const pNow = smp.p, vNow = smp.v;
  // draw arrow in 3D: from pNow to pNow + 0.22*vNow
  const pEnd = nrm(add(pNow, scale(vNow, 0.28)));
  const a = proj(pNow), b = proj(pEnd);
  ensureArrow(svg, 'pt-v', 'var(--green)');
  svg.appendChild(SVG('path',{d:`M${a[0]} ${a[1]} L ${b[0]} ${b[1]}`, stroke:'var(--green)','stroke-width':2.4,
    'marker-end':'url(#pt-v)', fill:'none'}));
  // starting reference vector (dashed, at A)
  const pS = proj(A);
  const ref = nrm(add(A, scale(v0, 0.28)));
  const pRef = proj(ref);
  svg.appendChild(SVG('path',{d:`M${pS[0]} ${pS[1]} L ${pRef[0]} ${pRef[1]}`, stroke:'var(--violet)','stroke-width':1.8,
    'stroke-dasharray':'3,3', fill:'none'}));

  // readout
  const area = sphArea(A,B,C);
  const hol = holonomy(v0);
  out.textContent =
    `holonomy rotation: ${(hol.angle*180/Math.PI).toFixed(1)}° (as predicted by area = ${(area*180/Math.PI).toFixed(1)}°)  · on S² with K=1, holonomy = area`;
}

function animate(){
  animT = 0;
  cancelAnimationFrame(animRAF);
  const t0 = performance.now();
  function step(ts){
    animT = Math.min(1, (ts - t0)/3000);
    render();
    if(animT < 1) animRAF = requestAnimationFrame(step);
  }
  animRAF = requestAnimationFrame(step);
}

play.addEventListener('click', animate);
reset.addEventListener('click', ()=>{
  verts = defaults.map(v=>v.slice());
  animT = 0;
  render();
});

// simple drag
svg.addEventListener('mousedown', ev=>{
  const rect = svg.getBoundingClientRect();
  const px = (ev.clientX - rect.left) * (W/rect.width);
  const py = (ev.clientY - rect.top) * (H/rect.height);
  for(let k=0;k<3;k++){
    const pr = proj(verts[k]);
    if(Math.hypot(pr[0]-px, pr[1]-py) < 14){
      dragging = k;
      return;
    }
  }
});
svg.addEventListener('mousemove', ev=>{
  if(dragging<0) return;
  const rect = svg.getBoundingClientRect();
  const px = (ev.clientX - rect.left) * (W/rect.width);
  const py = (ev.clientY - rect.top) * (H/rect.height);
  const p = unproject(px, py);
  if(p){
    verts[dragging] = nrm(p);
    animT = 0;
    render();
  }
});
svg.addEventListener('mouseup', ()=>{ dragging=-1; });
svg.addEventListener('mouseleave', ()=>{ dragging=-1; });

render();

