const svg = $('#geo-svg'), out = $('#geo-out'), TS = $('#geo-T'), TV = $('#geo-Tv'), CLR = $('#geo-clear');
const tabs = $$('#geo-tabs button');
const W=620, H=380;
let tab = 'sphere';
