// ---------- SPHERE projection (orthographic front-face) ----------
const S_CX=310, S_CY=190, S_R=155;
function sphToPixel(v){ // v: 3D unit vector
  // rotation about y by 0.3
  const A = 0.3; const sA=Math.sin(A), cA=Math.cos(A);
  const x = cA*v[0] + sA*v[2];
  const y = v[1];
  const z = -sA*v[0] + cA*v[2];
  return [S_CX + S_R*x, S_CY - S_R*y, z];
}
function pixelToSph(px,py){
  const x = (px - S_CX)/S_R, y = (S_CY - py)/S_R;
  const rr = x*x + y*y; if(rr>1) return null;
  const z0 = Math.sqrt(1-rr);
  const A = -0.3; const sA=Math.sin(A), cA=Math.cos(A);
  return [cA*x + sA*z0, y, -sA*x + cA*z0];
}
// tangent at p given screen direction (dx, dy)
function tangentFromScreen(p, dx, dy){
  // We want a tangent v to p such that when projected it points in direction (dx, dy).
  // Rotation used: cols of rotation
  // projected point = ( (cA*p[0]+sA*p[2])*S_R + S_CX,  S_CY - p[1]*S_R )
  // Varying p slightly by v, the projected differential is ( (cA*v[0]+sA*v[2])*S_R,  -v[1]*S_R )
  const A = 0.3; const sA=Math.sin(A), cA=Math.cos(A);
  // want (cA*vx + sA*vz, -vy) proportional to (dx, dy) (after dividing by S_R)
  // one solution: vx = dx*cA/(cA^2+sA^2) ... but we need vy=-dy and (cA*vx + sA*vz) = dx; v dot p = 0.
  // Pick vy = -dy (so that projected y matches).
  const vy = -dy/S_R;
  // Let vx = dx*cA/S_R; then sA*vz = dx/S_R - cA*vx = dx/S_R*(1-cA^2) = dx/S_R * sA^2 => vz = dx*sA/S_R
  const vx = dx*cA/S_R;
  const vz = dx*sA/S_R;
  // project out radial component
  let v = [vx, vy, vz];
  const d = v[0]*p[0]+v[1]*p[1]+v[2]*p[2];
  v = [v[0]-d*p[0], v[1]-d*p[1], v[2]-d*p[2]];
  return v;
}

// ---------- HYPERBOLIC half-plane ----------
const H_X0=40, H_X1=W-40, H_Y0=30, H_Y1=H-30;
// parameter range: x in [-2, 2], y in (0, 3]
const HX0=-2, HX1=2, HY0=0.06, HY1=3;
function hypToPixel(x,y){
  const px = H_X0 + (x-HX0)/(HX1-HX0)*(H_X1-H_X0);
  const py = H_Y1 - (y-HY0)/(HY1-HY0)*(H_Y1-H_Y0);
  return [px, py];
}
function pixelToHyp(px,py){
  const x = HX0 + (px-H_X0)/(H_X1-H_X0)*(HX1-HX0);
  const y = HY0 + (H_Y1-py)/(H_Y1-H_Y0)*(HY1-HY0);
  return [x,y];
}

// ---------- FLAT TORUS: [0,1]^2 square ----------
const T_MARGIN=40, T_SIZE = Math.min(W,H) - 2*T_MARGIN;
const T_X0 = (W - T_SIZE)/2, T_Y0 = (H - T_SIZE)/2;
function torusToPixel(u,v){
  return [T_X0 + u*T_SIZE, T_Y0 + (1-v)*T_SIZE];
}
function pixelToTorus(px,py){
  return [(px-T_X0)/T_SIZE, 1 - (py-T_Y0)/T_SIZE];
}

