// Geodesic samplers
function sphereGeodesic(p0, v0, T, steps=200){
  // great circle: gamma(t) = cos(|v|t) p + sin(|v|t)/|v| v  (v tangent to p)
  const vn = Math.hypot(v0[0],v0[1],v0[2]);
  if(vn < 1e-6) return [p0];
  const out = [];
  for(let i=0;i<=steps;i++){
    const t = T*i/steps;
    const c = Math.cos(vn*t), s = Math.sin(vn*t)/vn;
    const p = [c*p0[0]+s*v0[0], c*p0[1]+s*v0[1], c*p0[2]+s*v0[2]];
    out.push(p);
  }
  return out;
}
function hypGeodesic(p0, v0, T, steps=400){
  // (x,y); ds^2 = (dx^2+dy^2)/y^2.
  // Geodesics: vertical lines or circles with center on x-axis.
  // We integrate the geodesic ODE with unit-speed scaling; use RK4.
  // Christoffels: Γ^x_{xy} = Γ^x_{yx} = -1/y; Γ^y_{xx} = 1/y; Γ^y_{yy} = -1/y.
  let x=p0[0], y=p0[1], vx=v0[0], vy=v0[1];
  const out = [[x,y]];
  const dt = T/steps;
  function rhs(x,y,vx,vy){
    return {
      x: vx, y: vy,
      vx: -(-2/y)*vx*vy,     // -Γ^x_{ij} v^i v^j; with Γ^x_{xy}=Γ^x_{yx}=-1/y we get  -2*(-1/y)*vx*vy = +2 vx vy / y
      vy: -(1/y)*vx*vx - (-1/y)*vy*vy  // -(Γ^y_{xx} vx^2 + Γ^y_{yy} vy^2) = -(vx^2/y) + vy^2/y = (vy^2 - vx^2)/y
    };
  }
  for(let i=0;i<steps;i++){
    // RK4
    const k1 = rhs(x,y,vx,vy);
    const k2 = rhs(x+0.5*dt*k1.x, y+0.5*dt*k1.y, vx+0.5*dt*k1.vx, vy+0.5*dt*k1.vy);
    const k3 = rhs(x+0.5*dt*k2.x, y+0.5*dt*k2.y, vx+0.5*dt*k2.vx, vy+0.5*dt*k2.vy);
    const k4 = rhs(x+dt*k3.x,     y+dt*k3.y,     vx+dt*k3.vx,     vy+dt*k3.vy);
    x  += dt*(k1.x + 2*k2.x + 2*k3.x + k4.x)/6;
    y  += dt*(k1.y + 2*k2.y + 2*k3.y + k4.y)/6;
    vx += dt*(k1.vx + 2*k2.vx + 2*k3.vx + k4.vx)/6;
    vy += dt*(k1.vy + 2*k2.vy + 2*k3.vy + k4.vy)/6;
    if(y <= 0.01){ out.push([x,Math.max(y,0.01)]); break; }
    out.push([x,y]);
  }
  return out;
}
function torusGeodesic(p0, v0, T, steps=400){
  // flat metric; geodesic is a straight line, but wrap mod 1.
  // We emit segments; each segment is a polyline until we cross a boundary, then modwrap.
  const out = [];
  let seg = [[p0[0], p0[1]]];
  let x = p0[0], y = p0[1];
  const dx = v0[0], dy = v0[1];
  const dt = T/steps;
  for(let i=1;i<=steps;i++){
    let nx = x + dt*dx, ny = y + dt*dy;
    // detect boundary crossings: simple check; break segment at crossing
    if(nx > 1 || nx < 0 || ny > 1 || ny < 0){
      // find t_cross within this step
      let tc = 1;
      if(dx>0 && nx>1) tc = Math.min(tc, (1-x)/(nx-x));
      if(dx<0 && nx<0) tc = Math.min(tc, (0-x)/(nx-x));
      if(dy>0 && ny>1) tc = Math.min(tc, (1-y)/(ny-y));
      if(dy<0 && ny<0) tc = Math.min(tc, (0-y)/(ny-y));
      const xc = x + tc*(nx-x), yc = y + tc*(ny-y);
      seg.push([xc,yc]);
      out.push(seg);
      // wrap
      let xw = xc, yw = yc;
      if(xc >= 1-1e-6) xw = 0; else if(xc <= 1e-6) xw = 1;
      if(yc >= 1-1e-6) yw = 0; else if(yc <= 1e-6) yw = 1;
      // remaining fraction
      const remX = xw + (1-tc)*(nx-x);
      const remY = yw + (1-tc)*(ny-y);
      x = remX; y = remY;
      seg = [[xw, yw], [x, y]];
    } else {
      x = nx; y = ny;
      seg.push([x,y]);
    }
  }
  out.push(seg);
  return out; // list of polyline segments (parameter space)
}

function render(){
