    ensureArrow(svg, 'geo-drag', 'var(--cyan)');
    svg.appendChild(SVG('path',{d:`M${drag.x0} ${drag.y0} L ${drag.x1} ${drag.y1}`,
      stroke:'var(--cyan)', 'stroke-width':2, 'marker-end':'url(#geo-drag)', fill:'none'}));
  }
}

