const svg=$('#sec-svg'), out=$('#sec-out'), sp=$('#sec-sp'), ua=$('#sec-ua'), va=$('#sec-va');
const W=620, H=220;
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  svg.appendChild(SVG('rect',{x:0,y:0,width:W,height:H,fill:'#0b0f16'}));
  const uA = (+ua.value)*Math.PI/180, vA = (+va.value)*Math.PI/180;
  const CX=180, CY=110, RR=72;
  // tangent plane illustration
  svg.appendChild(SVG('circle',{cx:CX, cy:CY, r:RR, fill:'rgba(88,196,221,0.06)', stroke:'var(--line)'}));
  // u and v as arrows
  const u = [Math.cos(uA)*RR, -Math.sin(uA)*RR];
  const v = [Math.cos(vA)*RR, -Math.sin(vA)*RR];
  ensureArrow(svg,'sec-u','var(--yellow)');
  ensureArrow(svg,'sec-v','var(--cyan)');
  svg.appendChild(SVG('path',{d:`M${CX} ${CY} L ${CX+u[0]} ${CY+u[1]}`,
    stroke:'var(--yellow)','stroke-width':2.2, 'marker-end':'url(#sec-u)', fill:'none'}));
  svg.appendChild(SVG('path',{d:`M${CX} ${CY} L ${CX+v[0]} ${CY+v[1]}`,
    stroke:'var(--cyan)','stroke-width':2.2, 'marker-end':'url(#sec-v)', fill:'none'}));
  svg.appendChild(SVG('text',{x:CX+u[0]*1.15, y:CY+u[1]*1.15+5, 'font-size':14, fill:'var(--yellow)',
    'text-anchor':'middle', 'font-style':'italic'})).textContent='u';
  svg.appendChild(SVG('text',{x:CX+v[0]*1.15, y:CY+v[1]*1.15+5, 'font-size':14, fill:'var(--cyan)',
    'text-anchor':'middle', 'font-style':'italic'})).textContent='v';
  // plane label
  const tP = SVG('text',{x:CX, y:CY+RR+22, 'text-anchor':'middle', 'font-size':12, fill:'var(--mute)'});
  tP.textContent = 'tangent plane T_p M with vectors u, v';
