    const tb = SVG('text',{x:CX, y:H-30, 'text-anchor':'middle', 'font-size':12, fill:'var(--ink)'});
    tb.textContent = `Σθ = ${(sum*180/Math.PI).toFixed(1)}°  (exactly 180°)`;
    svg.appendChild(tb);
  }
  // ----- hyperbolic panel -----
  {
    const CX = 2*PANEL_W + PANEL_W/2, CY = H/2, R=95;
    svg.appendChild(SVG('circle',{cx:CX, cy:CY, r:R, fill:'rgba(224,122,95,0.05)', stroke:'var(--pink)', 'stroke-width':1.3}));
    const [A,B,C] = hypVerts;
    [[A,B],[B,C],[C,A]].forEach(([p,q])=>{
      const pts = hypArc(p,q);
      const d = pts.map((P,i)=>{
        const pr = hypToPx(P);
        return (i===0?'M':'L')+pr[0].toFixed(1)+' '+pr[1].toFixed(1);
      }).join(' ');
      svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--pink)', 'stroke-width':2}));
    });
    [A,B,C].forEach(p=>{
      const pr = hypToPx(p);
      svg.appendChild(SVG('circle',{cx:pr[0],cy:pr[1],r:6, fill:'var(--yellow)', stroke:'#111'}));
    });
    const sum = hypAngleAt(A,B,C)+hypAngleAt(B,A,C)+hypAngleAt(C,A,B);
    const area = hypArea(A,B,C);
    const tb = SVG('text',{x:CX, y:H-30, 'text-anchor':'middle', 'font-size':12, fill:'var(--ink)'});
    tb.textContent = `Σθ = ${(sum*180/Math.PI).toFixed(1)}°  (deficit ${((Math.PI-sum)*180/Math.PI).toFixed(1)}° = area)`;
    svg.appendChild(tb);
  }
}

function pix(ev){
  const r = svg.getBoundingClientRect();
  return [(ev.clientX-r.left)*(W/r.width), (ev.clientY-r.top)*(H/r.height)];
}
function panelOf(px){ if(px<PANEL_W) return 'sph'; if(px<2*PANEL_W) return 'flat'; return 'hyp'; }

svg.addEventListener('mousedown', ev=>{
  const [px,py] = pix(ev);
  const pn = panelOf(px);
  let verts, toPx;
  if(pn==='sph'){ verts=sphereVerts; toPx = sphToPx; }
  else if(pn==='flat'){ verts=flatVerts; toPx = flatToPx; }
  else { verts=hypVerts; toPx = hypToPx; }
  for(let k=0;k<3;k++){
    const pr = toPx(verts[k]);
    if(Math.hypot(pr[0]-px, pr[1]-py) < 12){
      drag = {panel:pn, idx:k};
      return;
    }
  }
});
svg.addEventListener('mousemove', ev=>{
  if(!drag) return;
  const [px,py] = pix(ev);
  if(drag.panel==='sph'){
    const v = pxToSph(px,py);
    if(v) sphereVerts[drag.idx] = v;
  } else if(drag.panel==='flat'){
    flatVerts[drag.idx] = pxToFlat(px,py);
  } else {
    let h = pxToHyp(px,py);
    const r = Math.hypot(h[0], h[1]);
    if(r > 0.95) h = [h[0]*0.95/r, h[1]*0.95/r];
    hypVerts[drag.idx] = h;
  }
  render();
});
svg.addEventListener('mouseup', ()=>{ drag=null; });
svg.addEventListener('mouseleave', ()=>{ drag=null; });

out.textContent = 'Drag any vertex. Sum of angles = π + K·(area) by Gauss–Bonnet for geodesic triangles on constant-curvature surfaces.';
render();

