  const A=-0.28, sA=Math.sin(A), cA=Math.cos(A);
  return [cA*x+sA*z0, y, -sA*x+cA*z0];
}
function flatToPx(p){
  const CX = PANEL_W + PANEL_W/2, CY = H/2, R = 90;
  return [CX + p[0]*R, CY - p[1]*R];
}
function pxToFlat(px,py){
  const CX = PANEL_W + PANEL_W/2, CY = H/2, R = 90;
  return [(px-CX)/R, (CY-py)/R];
}
function hypToPx(p){
  const CX = 2*PANEL_W + PANEL_W/2, CY = H/2, R = 95;
  return [CX + p[0]*R, CY - p[1]*R];
}
function pxToHyp(px,py){
  const CX = 2*PANEL_W + PANEL_W/2, CY = H/2, R = 95;
  return [(px-CX)/R, (CY-py)/R];
}

// --- geodesic samplers and angle computations ---
function sphereArc(a,b, n=40){
  const out=[];
  const c = Math.max(-1, Math.min(1, a[0]*b[0]+a[1]*b[1]+a[2]*b[2]));
  const omg = Math.acos(c);
  if(omg<1e-6) return [a];
  const s = Math.sin(omg);
  for(let i=0;i<=n;i++){
    const t=i/n;
    const p = [
      Math.sin((1-t)*omg)/s * a[0] + Math.sin(t*omg)/s * b[0],
      Math.sin((1-t)*omg)/s * a[1] + Math.sin(t*omg)/s * b[1],
      Math.sin((1-t)*omg)/s * a[2] + Math.sin(t*omg)/s * b[2],
    ];
    out.push(p);
  }
  return out;
}
function sphereAngleAt(P, Q, R){
  // angle at P between arcs PQ and PR
  function tan(P,X){
    // direction at P toward X along geodesic
    const c = P[0]*X[0]+P[1]*X[1]+P[2]*X[2];
    return [X[0]-c*P[0], X[1]-c*P[1], X[2]-c*P[2]];
  }
  const u = tan(P,Q), w = tan(P,R);
  const nu = Math.hypot(u[0],u[1],u[2]), nw = Math.hypot(w[0],w[1],w[2]);
  if(nu<1e-6 || nw<1e-6) return 0;
  const c = Math.max(-1, Math.min(1, (u[0]*w[0]+u[1]*w[1]+u[2]*w[2])/(nu*nw)));
  return Math.acos(c);
}
function sphereArea(A,B,C){
  return sphereAngleAt(A,B,C) + sphereAngleAt(B,A,C) + sphereAngleAt(C,A,B) - Math.PI;
}
function flatAngleAt(P, Q, R){
  const u=[Q[0]-P[0], Q[1]-P[1]];
  const w=[R[0]-P[0], R[1]-P[1]];
  const nu=Math.hypot(u[0],u[1]), nw=Math.hypot(w[0],w[1]);
  if(nu<1e-6||nw<1e-6) return 0;
  const c = Math.max(-1, Math.min(1, (u[0]*w[0]+u[1]*w[1])/(nu*nw)));
  return Math.acos(c);
}
// Poincaré disk: a geodesic between two interior points is a circular arc orthogonal to the boundary (or a diameter).
// We sample by parameterizing.  Pseudo-code using Möbius transformations:
// For points a,b in the open disk, the hyperbolic geodesic from a to b can be sampled by first translating a to 0 via Möbius, then interpolating along the straight line (diameter) to the translated b, and pulling back.
function mobiusNeg(a, z){
  // T_a(z) = (z - a)/(1 - \bar a z)   (complex), sends a -> 0
  // z,a complex = x + iy
  const [ax, ay] = a;
  const [zx, zy] = z;
  // numerator (z-a)
  const nx = zx - ax, ny = zy - ay;
  // denominator 1 - conj(a) z = 1 - (ax - i ay)(zx + i zy) = 1 - (ax*zx + ay*zy) + i(ay*zx - ax*zy)
  const dx = 1 - (ax*zx + ay*zy);
  const dy = -(ax*zy - ay*zx); // careful: conj(a) = ax - i ay, conj(a)*z = ax*zx + ay*zy + i(ax*zy - ay*zx)
  // wait recompute: conj(a)*z = (ax-i ay)(zx+i zy) = ax*zx + i ax*zy - i ay*zx + ay*zy (since -i^2=1)
  // = (ax*zx + ay*zy) + i(ax*zy - ay*zx)
  // so 1 - conj(a)*z has real = 1 - (ax*zx + ay*zy), imag = -(ax*zy - ay*zx) = ay*zx - ax*zy
  const Dx = 1 - (ax*zx + ay*zy);
  const Dy = ay*zx - ax*zy;
  // divide (nx, ny) / (Dx, Dy)
  const D2 = Dx*Dx + Dy*Dy || 1e-12;
  return [(nx*Dx + ny*Dy)/D2, (ny*Dx - nx*Dy)/D2];
}
function mobiusPos(a, z){
  // inverse: T_a^{-1}(w) = (w + a)/(1 + conj(a)*w)
  const [ax, ay] = a, [zx, zy] = z;
  const nx = zx + ax, ny = zy + ay;
  // 1 + conj(a)*z (same as above with minus flipped)
  const Dx = 1 + (ax*zx + ay*zy);
  const Dy = -(ay*zx - ax*zy);
  const D2 = Dx*Dx + Dy*Dy || 1e-12;
  return [(nx*Dx + ny*Dy)/D2, (ny*Dx - nx*Dy)/D2];
}
function hypArc(a,b, n=50){
  // send a to 0, interpolate along straight line to T_a(b), pull back
  const Tb = mobiusNeg(a, b);
  const out = [];
  for(let i=0;i<=n;i++){
    const t=i/n;
    const z = [t*Tb[0], t*Tb[1]];
    const p = mobiusPos(a, z);
    out.push(p);
  }
  return out;
}
function hypDist(a,b){
  // d(a,b) = artanh(|T_a(b)|)  gives half-distance; formula: d = 2 artanh(|T_a(b)|)
  const Tb = mobiusNeg(a, b);
  const r = Math.hypot(Tb[0], Tb[1]);
  const rc = Math.min(r, 0.99999);
  return 2*Math.atanh(rc);
}
function hypAngleAt(P,Q,R){
  // the hyperbolic angle at P equals the Euclidean angle between the initial tangents of the two geodesics at P in the disk model (conformal!)
  // so we can just take Euclidean tangents of arcs: arc from P to Q, first segment direction.
  const arcPQ = hypArc(P, Q, 2);
  const arcPR = hypArc(P, R, 2);
  const u = [arcPQ[1][0]-P[0], arcPQ[1][1]-P[1]];
  const w = [arcPR[1][0]-P[0], arcPR[1][1]-P[1]];
  const nu = Math.hypot(u[0],u[1]), nw = Math.hypot(w[0],w[1]);
  if(nu<1e-9 || nw<1e-9) return 0;
  const c = Math.max(-1, Math.min(1, (u[0]*w[0]+u[1]*w[1])/(nu*nw)));
  return Math.acos(c);
}
function hypArea(A,B,C){
  // Gauss-Bonnet: area = pi - sum(angles) for K = -1
  return Math.PI - (hypAngleAt(A,B,C) + hypAngleAt(B,A,C) + hypAngleAt(C,A,B));
}

