let drag = null;
function clearSvg(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  svg.appendChild(SVG('rect',{x:0,y:0,width:W,height:H,fill:'#0b0f16'}));
}
function render(){
  clearSvg();
  // panel separators
  for(let k=1;k<3;k++){
    svg.appendChild(SVG('line',{x1:k*PANEL_W, y1:10, x2:k*PANEL_W, y2:H-10, stroke:'var(--line)', 'stroke-width':1}));
  }
