    arcs.forEach(([p,q])=>{
      const pts = sphereArc(p,q);
      const d = pts.map((P,i)=>{
        const pr = sphToPx(P);
        return (i===0?'M':'L')+pr[0].toFixed(1)+' '+pr[1].toFixed(1);
      }).join(' ');
      svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--green)', 'stroke-width':2}));
    });
    [A,B,C].forEach((P,i)=>{
      const pr = sphToPx(P);
      svg.appendChild(SVG('circle',{cx:pr[0],cy:pr[1],r:6, fill:'var(--yellow)', stroke:'#111'}));
    });
    const sum = sphereAngleAt(A,B,C)+sphereAngleAt(B,A,C)+sphereAngleAt(C,A,B);
    const area = sphereArea(A,B,C);
    const tb = SVG('text',{x:CX, y:H-30, 'text-anchor':'middle', 'font-size':12, fill:'var(--ink)'});
    tb.textContent = `Σθ = ${(sum*180/Math.PI).toFixed(1)}°  (excess ${(area*180/Math.PI).toFixed(1)}° = area)`;
    svg.appendChild(tb);
  }
  // ----- flat panel -----
  {
    const CX = PANEL_W + PANEL_W/2, CY = H/2, R=90;
    svg.appendChild(SVG('circle',{cx:CX, cy:CY, r:R, fill:'rgba(255,216,102,0.04)', stroke:'var(--line)'}));
    const [A,B,C] = flatVerts;
    const verts = [A,B,C];
    const d = verts.map((p,i)=>{
