      svg.appendChild(SVG('circle',{cx:pr[0],cy:pr[1],r:6, fill:'var(--yellow)', stroke:'#111'}));
    });
    const sum = hypAngleAt(A,B,C)+hypAngleAt(B,A,C)+hypAngleAt(C,A,B);
    const area = hypArea(A,B,C);
    const tb = SVG('text',{x:CX, y:H-30, 'text-anchor':'middle', 'font-size':12, fill:'var(--ink)'});
    tb.textContent = `Σθ = ${(sum*180/Math.PI).toFixed(1)}°  (deficit ${((Math.PI-sum)*180/Math.PI).toFixed(1)}° = area)`;
    svg.appendChild(tb);
  }
}

function pix(ev){
  const r = svg.getBoundingClientRect();
  return [(ev.clientX-r.left)*(W/r.width), (ev.clientY-r.top)*(H/r.height)];
}
function panelOf(px){ if(px<PANEL_W) return 'sph'; if(px<2*PANEL_W) return 'flat'; return 'hyp'; }

svg.addEventListener('mousedown', ev=>{
  const [px,py] = pix(ev);
  const pn = panelOf(px);
  let verts, toPx;
  if(pn==='sph'){ verts=sphereVerts; toPx = sphToPx; }
  else if(pn==='flat'){ verts=flatVerts; toPx = flatToPx; }
  else { verts=hypVerts; toPx = hypToPx; }
  for(let k=0;k<3;k++){
    const pr = toPx(verts[k]);
    if(Math.hypot(pr[0]-px, pr[1]-py) < 12){
      drag = {panel:pn, idx:k};
      return;
    }
  }
});
svg.addEventListener('mousemove', ev=>{
  if(!drag) return;
  const [px,py] = pix(ev);
  if(drag.panel==='sph'){
    const v = pxToSph(px,py);
    if(v) sphereVerts[drag.idx] = v;
  } else if(drag.panel==='flat'){
    flatVerts[drag.idx] = pxToFlat(px,py);
  } else {
    let h = pxToHyp(px,py);
    const r = Math.hypot(h[0], h[1]);
    if(r > 0.95) h = [h[0]*0.95/r, h[1]*0.95/r];
    hypVerts[drag.idx] = h;
  }
  render();
});
svg.addEventListener('mouseup', ()=>{ drag=null; });
svg.addEventListener('mouseleave', ()=>{ drag=null; });

out.textContent = 'Drag any vertex. Sum of angles = π + K·(area) by Gauss–Bonnet for geodesic triangles on constant-curvature surfaces.';
render();

const svg=$('#jac-svg'), out=$('#jac-out'), dEl=$('#jac-d'), dVv=$('#jac-dv');
const W=660, H=320;

const SPH = {cx: 180, cy: 170, r: 130};
const PLT = {x0: 380, x1: 640, y0: 40, y1: 280};

function sphToPx(v){
  const A=0.25; const sA=Math.sin(A), cA=Math.cos(A);
  const x = cA*v[0] + sA*v[2];
  const y = v[1];
  return [SPH.cx + SPH.r*x, SPH.cy - SPH.r*y, -sA*v[0] + cA*v[2]];
}
// Geodesic from (0,1,0) with initial direction at azimuth phi and "polar" t
// gamma(t) = (sin t cos phi, cos t, sin t sin phi)
function arc(phi, T=Math.PI, n=80){
  const out = [];
  for(let i=0;i<=n;i++){
    const t = T*i/n;
    out.push([Math.sin(t)*Math.cos(phi), Math.cos(t), Math.sin(t)*Math.sin(phi)]);
  }
  return out;
}
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  svg.appendChild(SVG('rect',{x:0,y:0,width:W,height:H,fill:'#0b0f16'}));
  const d = +dEl.value;
  dVv.textContent = `δ = ${d.toFixed(2)} rad`;
  // sphere
  svg.appendChild(SVG('circle',{cx:SPH.cx, cy:SPH.cy, r:SPH.r, fill:'rgba(88,196,221,0.06)', stroke:'var(--line)'}));
  // latitudes
  for(let k=1;k<6;k++){
    const lat = -1 + k*2/6; const rr = Math.sqrt(1-lat*lat);
    svg.appendChild(SVG('ellipse',{cx:SPH.cx, cy:SPH.cy - lat*SPH.r, rx:rr*SPH.r*0.96, ry:rr*SPH.r*0.18,
      fill:'none', stroke:'var(--line)', 'stroke-width':0.7}));
  }
  // geodesic 1: phi = 0
  const g1 = arc(0);
  // geodesic 2: phi = delta
  const g2 = arc(d);
  // draw each; switch to dashed when behind (z<0). We'll draw visible segments solid, invisible dashed.
  function drawArc(pts, color){
    let inFront = null; let subpath = [];
    const segs = [];
    for(let i=0;i<pts.length;i++){
      const pr = sphToPx(pts[i]);
      const front = pr[2] >= 0;
      if(inFront===null || front===inFront){
        subpath.push(pr);
      } else {
        segs.push({front:inFront, pts:subpath});
        subpath = [pr];
      }
      inFront = front;
    }
    if(subpath.length) segs.push({front:inFront, pts:subpath});
    segs.forEach(s=>{
      const d = s.pts.map((p,i)=>(i===0?'M':'L')+p[0].toFixed(1)+' '+p[1].toFixed(1)).join(' ');
      const p = SVG('path',{d, fill:'none', stroke:color, 'stroke-width':2});
      if(!s.front) p.setAttribute('stroke-dasharray','3,3');
      svg.appendChild(p);
    });
  }
  drawArc(g1, 'var(--yellow)');
  drawArc(g2, 'var(--cyan)');
  // labels
  const pN = sphToPx([0,1,0]);
  svg.appendChild(SVG('circle',{cx:pN[0], cy:pN[1], r:4, fill:'var(--green)'}));
  const tN = SVG('text',{x:pN[0]+10, y:pN[1]-6, 'font-size':12, fill:'var(--green)'});
  tN.textContent='N'; svg.appendChild(tN);
  const pS = sphToPx([0,-1,0]);
  svg.appendChild(SVG('circle',{cx:pS[0], cy:pS[1], r:4, fill:'var(--pink)'}));
  const tS = SVG('text',{x:pS[0]+10, y:pS[1]+14, 'font-size':12, fill:'var(--pink)'});
  tS.textContent='S (conjugate)'; svg.appendChild(tS);

  // separation segments at several t
  const tSamples = [Math.PI*0.25, Math.PI*0.5, Math.PI*0.75];
  tSamples.forEach(t=>{
    const p1 = [Math.sin(t), Math.cos(t), 0];
    const p2 = [Math.sin(t)*Math.cos(d), Math.cos(t), Math.sin(t)*Math.sin(d)];
    const a = sphToPx(p1), b = sphToPx(p2);
    svg.appendChild(SVG('path',{d:`M${a[0]} ${a[1]} L ${b[0]} ${b[1]}`, stroke:'var(--violet)',
      'stroke-width':1.4}));
  });

  // right panel: |J|(t) = sin(t) * delta (since |J|(0)=0, |J|'(0)=delta for initial tangent angular spread delta)
  svg.appendChild(SVG('rect',{x:PLT.x0-10, y:PLT.y0-10, width:PLT.x1-PLT.x0+20, height:PLT.y1-PLT.y0+20,
    fill:'var(--panel2)', stroke:'var(--line)'}));
  // axes
  const xax = SVG('line',{x1:PLT.x0, y1:PLT.y1, x2:PLT.x1, y2:PLT.y1, stroke:'var(--mute)', 'stroke-width':1});
  const yax = SVG('line',{x1:PLT.x0, y1:PLT.y0, x2:PLT.x0, y2:PLT.y1, stroke:'var(--mute)', 'stroke-width':1});
  svg.appendChild(xax); svg.appendChild(yax);
  const xMax = Math.PI;
  const yMax = d * 1.1; // scale
  function mapXY(t, v){
    return [PLT.x0 + (t/xMax)*(PLT.x1-PLT.x0), PLT.y1 - (v/Math.max(yMax, 0.05))*(PLT.y1-PLT.y0)];
  }
  // plot: |J| = sin(t) * delta for t in [0, pi]
  const pts = [];
  for(let i=0;i<=120;i++){
    const t = xMax*i/120;
    pts.push([t, Math.sin(t)*d]);
  }
  const pd = pts.map((p,i)=>{
    const xy = mapXY(p[0], p[1]);
    return (i===0?'M':'L')+xy[0].toFixed(1)+' '+xy[1].toFixed(1);
  }).join(' ');
  svg.appendChild(SVG('path',{d:pd, fill:'none', stroke:'var(--yellow)', 'stroke-width':2}));
  // t markers at π/4, π/2, 3π/4, π
  const ticks = [0, Math.PI/4, Math.PI/2, 3*Math.PI/4, Math.PI];
  const tlbl = ['0','π/4','π/2','3π/4','π'];
  ticks.forEach((t,k)=>{
    const xy = mapXY(t, 0);
    svg.appendChild(SVG('line',{x1:xy[0], y1:xy[1], x2:xy[0], y2:xy[1]+4, stroke:'var(--mute)'}));
    const lbl = SVG('text',{x:xy[0], y:xy[1]+18, 'text-anchor':'middle', 'font-size':11, fill:'var(--mute)'});
    lbl.textContent = tlbl[k];
    svg.appendChild(lbl);
  });
  // title
  const ttl = SVG('text',{x:(PLT.x0+PLT.x1)/2, y:PLT.y0-4, 'text-anchor':'middle', 'font-size':12, fill:'var(--yellow)'});
  ttl.textContent = '|J|(t) = δ sin(t)'; svg.appendChild(ttl);
  // markers at sampled t
  tSamples.forEach(t=>{
    const xy = mapXY(t, Math.sin(t)*d);
    svg.appendChild(SVG('circle',{cx:xy[0], cy:xy[1], r:4, fill:'var(--violet)'}));
  });
  // max
  const xyMax = mapXY(Math.PI/2, d);
  svg.appendChild(SVG('circle',{cx:xyMax[0], cy:xyMax[1], r:5, fill:'var(--green)'}));
  const tMax = SVG('text',{x:xyMax[0]+8, y:xyMax[1]-6, 'font-size':11, fill:'var(--green)'});
  tMax.textContent = `max = δ = ${d.toFixed(2)}`; svg.appendChild(tMax);

  out.textContent =
    `On S² (K=+1): along a unit-speed great circle, the transverse Jacobi field has magnitude δ·sin(t). It vanishes at t=0 and t=π (conjugate pair), with max δ at the equator.`;
}
dEl.addEventListener('input', render);
